      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let membersStore = {};

function create(projectId, memberData) {
  if (!membersStore[projectId]) {
    membersStore[projectId] = [];
  }
  const newMember = { id: randomUUID(), ...memberData };
  membersStore[projectId].push(newMember);
  return newMember;
}

function getAll(projectId) {
  return membersStore[projectId] || [];
}

module.exports = {
  create,
  getAll
};
